const LOGSEQ_ICON_PNG_BASE64 = "";

export function logseqMcpIcons(request) {
  return [{
    src: new URL("/mcp/icon.png", request.url).href,
    mimeType: "image/png",
    sizes: ["192x192"],
  }];
}

export function setLogseqMcpServerInfoIcons(server, request) {
  server.server._serverInfo = {
    ...server.server._serverInfo,
    icons: logseqMcpIcons(request),
  };
}

function base64ToBytes(base64) {
  const raw = atob(base64);
  const payload = new Uint8Array(raw.length);
  for (let i = 0; i < raw.length; i += 1) {
    payload[i] = raw.charCodeAt(i);
  }
  return payload;
}

export function logseqIconResponse() {
  return new Response(base64ToBytes(LOGSEQ_ICON_PNG_BASE64), {
    headers: {
      "cache-control": "public, max-age=86400",
      "content-type": "image/png",
    },
  });
}
